const items = $input.all();

function collectText(value, acc) {
  if (value == null) return;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (trimmed) acc.push(trimmed);
    return;
  }
  if (Array.isArray(value)) {
    for (const entry of value) collectText(entry, acc);
    return;
  }
  if (typeof value === 'object') {
    for (const key of ['text', 'fallback', 'title', 'pretext']) {
      if (value[key]) collectText(value[key], acc);
    }
    if (value.blocks) collectText(value.blocks, acc);
    if (value.elements) collectText(value.elements, acc);
    if (value.fields) collectText(value.fields, acc);
    if (value.attachments) collectText(value.attachments, acc);
    if (value.message) collectText(value.message, acc);
    if (value.previous_message) collectText(value.previous_message, acc);
  }
}

return items.map((item) => {
  const source = item.json || {};
  const chunks = [];
  collectText(source.text, chunks);
  collectText(source.blocks, chunks);
  collectText(source.attachments, chunks);
  collectText(source.message, chunks);
  collectText(source.previous_message, chunks);

  const textoCompleto = chunks.join('\n').replace(/\n{3,}/g, '\n\n').trim();

  return {
    json: {
      ...source,
      textoCompleto,
      payloadResumen: textoCompleto.slice(0, 1200),
    },
    pairedItem: item.pairedItem,
  };
});

const items = $input.all();

function firstMatch(text, regex, fallback = null) {
  const match = text.match(regex);
  return match ? match[1].trim() : fallback;
}

function normalizeMail(raw) {
  if (!raw) return null;
  const mailto = raw.match(/<mailto:([^|>]+)(?:\|[^>]+)?>/i);
  return mailto ? mailto[1].trim() : raw.trim();
}

return items.map((item) => {
  const text = item.json.textoCompleto || '';
  const lowered = text
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  if (!text) {
    return { json: { ...item.json, ok: false, stage: 'extract', error: 'No se encontró texto util en el payload de Slack' } };
  }

  const guia = firstMatch(text, /gu[ií]a\s*(\d{8,})/i);
  const usuario = normalizeMail(firstMatch(text, /USUARIO:\s*(.+)/i));
  const paqueteria = firstMatch(text, /PAQUETERIA:\s*(.+)/i);
  const servicio = firstMatch(text, /SERVICIO:\s*(.+)/i);
  const novedad = firstMatch(text, /NOVEDAD:\s*([\s\S]*?)(?=\*?--DESTINO--\*?|$)/i, '');
  const ciudad = firstMatch(text, /CIUDAD:\s*(.+)/i);
  const direccion = firstMatch(text, /DIRECCI[ÓO]N:\s*(.+)/i);
  const depApto = firstMatch(text, /DEP\/APTO:\s*(.+)/i, '');
  const zipCode = firstMatch(text, /ZIP_CODE:\s*(.+)/i, '');
  const telefono = firstMatch(text, /TEL[EÉ]FONO:\s*([+()\d\s.-]+)/i);

  const esProblemaDestinatario = lowered.includes('problema con el destinatario') || lowered.includes('no logra encontrar la direccion') || lowered.includes('direccion esta incompleta');

  if (!esProblemaDestinatario) {
    return {
      json: {
        ...item.json,
        ok: false,
        stage: 'filter',
        error: 'La novedad no corresponde a problema con el destinatario',
        guia: guia || null,
        tipoResultado: 'ignored',
      },
    };
  }

  const missing = [];
  if (!guia) missing.push('guia');
  if (!ciudad) missing.push('ciudad');
  if (!telefono) missing.push('telefono');
  if (!novedad) missing.push('novedad');

  if (missing.length) {
    return {
      json: {
        ...item.json,
        ok: false,
        stage: 'extract',
        error: 'Faltan campos requeridos: ' + missing.join(', '),
        guia: guia || null,
        usuario: usuario || null,
        paqueteria: paqueteria || null,
        servicio: servicio || null,
      },
    };
  }

  return {
    json: {
      ...item.json,
      ok: true,
      guia,
      usuario,
      paqueteria,
      servicio,
      novedad,
      ciudad,
      direccion,
      dep_apto: depApto,
      zip_code: zipCode,
      telefono,
      tipoNovedad: 'problema_destinatario',
    },
  };
});

const items = $input.all();

return items.map((item) => {
  const j = { ...item.json };
  const telefonoOriginal = String(j.telefono || '');
  let telefono = telefonoOriginal.replace(/\D/g, '');

  if (telefono.length === 10) telefono = '57' + telefono;

  const ciudadOriginal = String(j.ciudad || '').trim();
  const ciudadBase = ciudadOriginal.split('(')[0].trim();

  if (!telefono || telefono.length < 12) {
    return {
      json: {
        ...j,
        ok: false,
        stage: 'normalize',
        error: 'Telefono invalido tras normalizacion',
        telefonoOriginal,
      },
    };
  }

  return {
    json: {
      ...j,
      ok: true,
      telefonoOriginal,
      telefono,
      ciudadOriginal,
      ciudad: ciudadBase || ciudadOriginal,
      direccionOriginal: j.direccion || '',
    },
  };
});

const items = $input.all();

return items.map((item) => {
  const j = { ...item.json };

  // 1. Validación de datos críticos
  if (!j.telefono || !j.guia || !j.ciudad) {
    return {
      json: {
        ...j,
        ok: false,
        stage: 'compose',
        error: 'Faltan datos críticos para construir el mensaje',
      },
    };
  }

  const paqueteria = j.paqueteria || 'La transportadora';

  // 2. Limpieza del teléfono para el link de WhatsApp (Elimina cualquier cosa que no sea número)
  const telefonoLimpio = String(j.telefono).replace(/\D/g, '');

  // 3. Construcción del mensaje (Se usa \n para los saltos de línea correctos en código)
const mensaje = [
    'Hola, tu envío con guía *' + j.guia + '* presenta una novedad.',
    '',
    paqueteria + ' no logra encontrar la dirección de entrega 📍. Por favor, confirma la siguiente información:',
    '',
    '*Dirección:*',
    '*Complementos (torre, apartamento, piso, etc):*',
    '*Barrio:*',
    '*Ciudad/municipio de entrega:*',
    '*Puntos de referencia:*',
    '',
    'Esto nos ayudará a ubicar la dirección correcta y realizar la entrega de manera efectiva. '
  ].join('\n'); // <--- Aquí estaba el error. Debe usarse \n

  // 4. Retorno de datos con el enlace de WhatsApp codificado
  return {
    json: {
      ...j,
      ok: true,
      mensajeWhatsapp: mensaje,
      // Se genera el link usando el teléfono limpio y el texto codificado para URL
      enlaceWhatsapp: 'https://wa.me/' + telefonoLimpio + '?text=' + encodeURIComponent(mensaje),
      canal: j.channel || null,
      timestampSlack: j.ts || j.event_ts || null,
      workflow: 'novedadDestinatarioDireccion',
    },
  };
});

const source = $json || {};
const error = source.error || 'Error no especificado';

return [{
  json: {
    ok: false,
    workflow: 'novedadDestinatarioDireccion',
    stage: source.stage || 'unknown',
    error,
    guia: source.guia || null,
    payloadResumen: source.payloadResumen || (source.textoCompleto || '').slice(0, 1200),
    timestamp: new Date().toISOString(),
  },
}];

